/// Simple UUID v4 generator using Dart's Random class.
/// Generates RFC 4122 compliant version 4 UUIDs.
class UUIDGenerator {
  static final Random _random = Random.secure();

  /// Generate a single UUID v4 string.
  static String generateV4() {
    final bytes = List<int>.generate(16, (_) => _random.nextInt(256));

    // Set version to 4 (0100 in binary) in byte 6
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122 (10xx in binary) in byte 8
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).toList();

    return '${hex.sublist(0, 4).join('')}-'
        '${hex.sublist(4, 6).join('')}-'
        '${hex.sublist(6, 8).join('')}-'
        '${hex.sublist(8, 10).join('')}-'
        '${hex.sublist(10, 16).join('')}';
  }

  /// Generate a shorter unique ID (useful for compact identifiers).
  static String generateShort({int length = 12}) {
    const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
    return List.generate(length, (_) => chars[_random.nextInt(chars.length)])
        .join();
  }

  /// Generate a timestamp-prefixed UUID for sortable offline entries.
  static String generateTimestamped() {
    final now = DateTime.now().millisecondsSinceEpoch;
    final timestampHex = now.toRadixString(16).padLeft(12, '0');
    final randomPart = List<int>.generate(10, (_) => _random.nextInt(256));
    final randomHex =
        randomPart.map((b) => b.toRadixString(16).padLeft(2, '0')).join();

    return '${timestampHex.substring(0, 8)}-'
        '${timestampHex.substring(8, 12)}-'
        '${randomHex.substring(0, 4)}-'
        '${randomHex.substring(4, 8)}-'
        '${randomHex.substring(8, 20)}';
  }
}

/// Represents an offline data entry with a generated UUID.
class OfflineEntry {
  final String id;
  final String title;
  final String description;
  final DateTime createdAt;
  final String idType;
  bool isSynced;

  OfflineEntry({
    required this.id,
    required this.title,
    required this.description,
    required this.createdAt,
    required this.idType,
    this.isSynced = false,
  });
}

class UUIDGeneratorScreen extends StatefulWidget {
  const UUIDGeneratorScreen({super.key});

  @override
  State<UUIDGeneratorScreen> createState() => _UUIDGeneratorScreenState();
}

class _UUIDGeneratorScreenState extends State<UUIDGeneratorScreen>
    with SingleTickerProviderStateMixin {
  late TabController _tabController;
  final List<OfflineEntry> _entries = [];
  final List<String> _generatedUUIDs = [];
  String _selectedIdType = 'UUID v4';

  @override
  void initState() {
    super.initState();
    _tabController = TabController(length: 3, vsync: this);
    // Generate some initial UUIDs
    _generateBatchUUIDs(5);
  }

  @override
  void dispose() {
    _tabController.dispose();
    super.dispose();
  }

  void _generateBatchUUIDs(int count) {
    setState(() {
      for (int i = 0; i < count; i++) {
        _generatedUUIDs.add(_generateIdByType(_selectedIdType));
      }
    });
  }

  String _generateIdByType(String type) {
    switch (type) {
      case 'UUID v4':
        return UUIDGenerator.generateV4();
      case 'Short ID':
        return UUIDGenerator.generateShort();
      case 'Timestamped':
        return UUIDGenerator.generateTimestamped();
      default:
        return UUIDGenerator.generateV4();
    }
  }

  void _copyToClipboard(String text) {
    Clipboard.setData(ClipboardData(text: text));
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('Copied: $text'),
        duration: const Duration(seconds: 1),
        behavior: SnackBarBehavior.floating,
      ),
    );
  }

  void _showCreateEntryDialog() {
    final titleController = TextEditingController();
    final descController = TextEditingController();
    String dialogIdType = _selectedIdType;

    showDialog(
      context: context,
      builder: (context) {
        return StatefulBuilder(
          builder: (context, setDialogState) {
            final previewId = _generateIdByType(dialogIdType);
            return AlertDialog(
              title: const Text('Create Offline Entry'),
              content: SingleChildScrollView(
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.start,
